module top_module(
        input   wire [31:0]   op1,
        input   wire [31:0]   op2,
        input   wire [2:0]    operation,
        output  wire          res
    );reg invalid_result;

    always @ *
    case (operation)
        3'b000: invalid_result = (op1 ==  op2); 
        3'b010: invalid_result = (op1 >   op2);
        3'b101, 
        3'b110: invalid_result = (op1 <   op2);
        default: invalid_result = 1'bx;
    endcase

    assign res = invalid_result;

endmodule
